@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<div @ref="_el" id="@_chipId" class="@CssClass" @onclick="HandleClick" @onkeydown="HandleKeyDown" @attributes="AdditionalAttributes" role="@(Clickable ? "button" : null)" tabindex="@(Clickable ? "0" : null)" aria-disabled="@(Clickable && Disabled ? "true" : null)">
    @if (!string.IsNullOrEmpty(Avatar))
    {
        <img src="@Avatar" alt="" class="@AvatarSizeClass rounded-full object-cover shrink-0" />
    }
    else if (!string.IsNullOrEmpty(Icon))
    {
        <span class="shrink-0 text-current opacity-70">@Icon</span>
    }
    else if (IconContent is not null)
    {
        <span class="inline-flex items-center shrink-0">@IconContent</span>
    }

    <span>@ChildContent</span>

    @if (Closable)
    {
        <button type="button"
                class="relative shrink-0 inline-flex items-center justify-center cursor-pointer rounded-[calc(var(--radius)*2)] hover:bg-foreground/20 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring ms-0.5 h-5 w-5 before:absolute before:content-[''] before:-inset-2 before:rounded-full"
                @onclick="HandleClose"
                @onclick:stopPropagation="true"
                aria-label="@L["Chip.Remove"]">
            <SvgGlyph Svg="@(LumeoIcons.X)" class="@CloseIconSize" />
        </button>
    }
</div>

@code {
    /// <summary>The chip's label content, wrapped in a <c>&lt;span&gt;</c> between the
    /// leading icon/avatar and the close button.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>
    /// Optional leading icon slot. Rendered before <see cref="ChildContent"/> inside an
    /// <c>inline-flex items-center shrink-0</c> wrapper so sized content (e.g. a
    /// colour-dot <c>&lt;span&gt;</c>) retains its explicit dimensions. Only active when
    /// neither <see cref="Avatar"/> nor <see cref="Icon"/> is set.
    /// </summary>
    [Parameter] public RenderFragment? IconContent { get; set; }

    /// <summary>Surface style: <see cref="ChipVariant.Default"/> is a filled
    /// <c>bg-secondary</c> pill, <see cref="ChipVariant.Outline"/> is bordered with a
    /// transparent fill, and <see cref="ChipVariant.Solid"/> fills with the palette
    /// selected by <see cref="Color"/>.</summary>
    [Parameter] public ChipVariant Variant { get; set; } = ChipVariant.Default;
    /// <summary>Palette used by <see cref="ChipVariant.Solid"/> — one of <c>primary</c>,
    /// <c>destructive</c>, <c>success</c>, or <c>warning</c>. Any other value (including
    /// <c>null</c>) falls back to the secondary palette.</summary>
    [Parameter] public string? Color { get; set; }
    /// <summary>Chip size, driving text size, corner radius, avatar/close-icon dimensions,
    /// and (together with <see cref="Density"/>) the padding.</summary>
    [Parameter] public Lumeo.Size Size { get; set; } = Lumeo.Size.Md;
    /// <summary>Per-chip density override. When null, inherits from any
    /// ancestor <see cref="DensityScope"/>; if neither is set, matches the
    /// historical <c>Comfortable</c> default. Only the padding shifts — text
    /// size + radius stay governed by <see cref="Size"/>.</summary>
    [Parameter] public Density? Density { get; set; }
    [CascadingParameter] private Density? InheritedDensity { get; set; }
    /// <summary>Shows a trailing remove (X) button. Clicking it invokes
    /// <see cref="OnClose"/> instead of <see cref="OnClick"/> (the click is stopped from
    /// propagating to the chip itself).</summary>
    [Parameter] public bool Closable { get; set; }
    /// <summary>Raised when the remove (X) button is clicked. Has no effect while
    /// <see cref="Disabled"/> is <c>true</c>.</summary>
    [Parameter] public EventCallback OnClose { get; set; }
    /// <summary>Makes the chip itself an interactive <c>role="button"</c> surface —
    /// clickable and keyboard-activatable (Enter/Space) — invoking <see cref="OnClick"/>.</summary>
    [Parameter] public bool Clickable { get; set; }
    /// <summary>Raised on click or Enter/Space when <see cref="Clickable"/> is
    /// <c>true</c>. Has no effect while <see cref="Disabled"/> is <c>true</c>.</summary>
    [Parameter] public EventCallback OnClick { get; set; }
    /// <summary>Disables the chip: suppresses <see cref="OnClick"/> and
    /// <see cref="OnClose"/>, and applies a dimmed, non-interactive style.</summary>
    [Parameter] public bool Disabled { get; set; }
    /// <summary>Leading icon glyph string, rendered before <see cref="ChildContent"/>.
    /// Ignored when <see cref="Avatar"/> is set; takes precedence over <see cref="IconContent"/>.</summary>
    [Parameter] public string? Icon { get; set; }
    /// <summary>Leading avatar image URL, rendered as a rounded thumbnail before
    /// <see cref="ChildContent"/>. Takes precedence over <see cref="Icon"/> and <see cref="IconContent"/>.</summary>
    [Parameter] public string? Avatar { get; set; }

    /// <summary>
    /// Visual feedback when the chip is pressed (only applies when
    /// <see cref="Clickable"/> is <c>true</c>). Default is
    /// <see cref="Button.ButtonPressEffect.None"/>.
    /// </summary>
    [Parameter] public Button.ButtonPressEffect PressEffect { get; set; } = Button.ButtonPressEffect.None;

    /// <summary>Additional CSS classes merged onto the chip's root <c>div</c>, after the
    /// size/variant/interactive classes.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the root <c>div</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private Microsoft.AspNetCore.Components.ElementReference _el;
    private readonly string _chipId = LumeoIds.New("chip");

    private string? PressEffectClass => PressEffect switch
    {
        Button.ButtonPressEffect.Scale => "lumeo-press-scale",
        Button.ButtonPressEffect.Brightness => "lumeo-press-brightness",
        Button.ButtonPressEffect.Ripple => "lumeo-press-ripple",
        _ => null
    };

    private string CssClass => Cx.Merge(
        "inline-flex items-center gap-1 font-medium transition-colors",
        SizeClass,
        VariantClass,
        Cx.When(Clickable && !Disabled, "cursor-pointer hover:opacity-80 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"),
        Clickable && !Disabled ? PressEffectClass : null,
        Cx.When(Disabled, "opacity-50 pointer-events-none cursor-not-allowed"),
        Class);

    private Lumeo.Density EffectiveDensity => Density ?? InheritedDensity ?? Lumeo.Density.Comfortable;

    // Text + radius stay keyed on Size; only the padding varies with density.
    // Comfortable reproduces the historical per-Size padding verbatim.
    private string SizeClass => Size switch
    {
        Lumeo.Size.Xxs => $"text-[10px] {PadClass} rounded",
        Lumeo.Size.Sm => $"text-xs {PadClass} rounded-md",
        Lumeo.Size.Lg => $"text-sm {PadClass} rounded-lg",
        _ => $"text-sm {PadClass} rounded-md"
    };

    private string PadClass => (Size, EffectiveDensity) switch
    {
        (Lumeo.Size.Xxs, Lumeo.Density.Compact)  => "px-1 py-0",
        (Lumeo.Size.Xxs, Lumeo.Density.Spacious) => "px-2 py-0.5",
        (Lumeo.Size.Xxs, _)                      => "px-1.5 py-0",
        (Lumeo.Size.Sm, Lumeo.Density.Compact)   => "px-1.5 py-0",
        (Lumeo.Size.Sm, Lumeo.Density.Spacious)  => "px-2.5 py-1",
        (Lumeo.Size.Sm, _)                       => "px-2 py-0.5",
        (Lumeo.Size.Lg, Lumeo.Density.Compact)   => "px-2.5 py-0.5",
        (Lumeo.Size.Lg, Lumeo.Density.Spacious)  => "px-4 py-1.5",
        (Lumeo.Size.Lg, _)                       => "px-3 py-1",
        (_, Lumeo.Density.Compact)               => "px-2 py-0",
        (_, Lumeo.Density.Spacious)              => "px-3 py-1",
        _                                        => "px-2.5 py-0.5"
    };

    private string VariantClass => Variant switch
    {
        ChipVariant.Outline => "border border-border/40 bg-transparent text-foreground",
        ChipVariant.Solid => GetSolidClass(),
        _ => "bg-secondary text-secondary-foreground"
    };

    private string GetSolidClass() => Color switch
    {
        "primary" => "bg-primary text-primary-foreground",
        "destructive" => "bg-destructive text-destructive-foreground",
        "success" => "bg-success-light text-success-text",
        "warning" => "bg-warning-light text-warning-text",
        _ => "bg-secondary text-secondary-foreground"
    };

    private string AvatarSizeClass => Size switch
    {
        Lumeo.Size.Xxs => "h-3 w-3",
        Lumeo.Size.Sm => "h-4 w-4",
        Lumeo.Size.Lg => "h-6 w-6",
        _ => "h-5 w-5"
    };

    private string CloseIconSize => Size switch
    {
        Lumeo.Size.Xxs => "h-2.5 w-2.5",
        Lumeo.Size.Sm => "h-3 w-3",
        _ => "h-3.5 w-3.5"
    };

    private async Task HandleClick()
    {
        if (Disabled) return;
        if (Clickable) await OnClick.InvokeAsync();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (!Clickable || Disabled) return;
        if (e.Key is "Enter" or " ") await OnClick.InvokeAsync();
    }

    private async Task HandleClose()
    {
        if (Disabled) return;
        await OnClose.InvokeAsync();
    }

    // Whether the JS pointerdown ripple listener is currently bound to _el.
    // Reconciled against the live Clickable/PressEffect on EVERY render — not
    // latched on firstRender — and torn down on dispose (triage #33).
    private bool _rippleAttached;

    // Whether the Space-key preventDefault rule is registered for this chip's
    // role=button surface. A div[role=button] has no native key synthesis, so
    // Space both activated the chip AND scrolled the page; the rule suppresses
    // only Space's default while Clickable (Enter has no default on a div).
    // Reconciled per-render and torn down on dispose (triage #7).
    private bool _pdRegistered;

    private bool NeedsRipple => Clickable && PressEffect == Button.ButtonPressEffect.Ripple;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Reconcile the ripple listener with the current Clickable/PressEffect,
        // not just the first-render value: a runtime None/Clickable->Ripple flip
        // must now attach, and a Ripple->None flip must detach the leaked
        // listener (triage #33, copying Button.razor's proven reconcile logic).
        if (NeedsRipple && !_rippleAttached)
        {
            try
            {
                await Interop.RippleAttachAsync(_el);
                _rippleAttached = true;
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
        else if (!NeedsRipple && _rippleAttached)
        {
            try
            {
                await Interop.RippleDetachAsync(_el);
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            _rippleAttached = false;
        }

        // Suppress Space's page-scroll default while the chip is a role=button
        // surface (triage #7). Reconciled so a Clickable flip wires/unwires it.
        if (Clickable && !_pdRegistered)
        {
            try
            {
                await Interop.RegisterPreventDefaultKeys(
                    _chipId,
                    new[] { new Lumeo.Services.PreventDefaultKeyRule(" ") });
                _pdRegistered = true;
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            catch (InvalidOperationException) { } // JS interop unavailable during prerender
        }
        else if (!Clickable && _pdRegistered)
        {
            try
            {
                await Interop.UnregisterPreventDefaultKeys(_chipId);
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
            catch (InvalidOperationException) { }
            _pdRegistered = false;
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_rippleAttached)
        {
            try
            {
                await Interop.RippleDetachAsync(_el);
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            _rippleAttached = false;
        }
        if (_pdRegistered)
        {
            try
            {
                await Interop.UnregisterPreventDefaultKeys(_chipId);
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
            catch (InvalidOperationException) { }
            _pdRegistered = false;
        }
    }

    public enum ChipVariant { Default, Outline, Solid }
}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    /// <summary>The group's <see cref="Chip"/> children, laid out in a wrapping flex
    /// row.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Additional CSS classes merged onto the group's root <c>div</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the root <c>div</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("flex flex-wrap gap-1.5", Class);
}
